// ─── STAT ────────────────────────────────────────────────────────────────────
function Stat({ num, label, suffix="+", visible }) {
  const val = useCounter(num, visible);
  return (
    <div style={{ background:"#0a0a0a", padding:"28px 24px" }}>
      <div style={{ fontFamily:"'Space Grotesk',sans-serif", fontSize:38, fontWeight:700, letterSpacing:"-.04em", marginBottom:6 }}>
        {val}{suffix}
      </div>
      <div style={{ fontSize:11, letterSpacing:".08em", textTransform:"uppercase", color:"#6b6b6b" }}>{label}</div>
    </div>
  );
}

